// And groups predicates with the AND operator between them.
func And(predicates ...predicate.QualityInspection) predicate.QualityInspection {
	return predicate.QualityInspection(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.QualityInspection) predicate.QualityInspection {
	return predicate.QualityInspection(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.QualityInspection) predicate.QualityInspection {
	return predicate.QualityInspection(sql.NotPredicates(p))
}
